const { exec } = require('child_process');
const util = require('util');
const execAsync = util.promisify(exec);
return execAsync('python scripts/normalize_apollo.py', { cwd: process.cwd(), encoding: 'utf8', maxBuffer: 1024 * 1024 * 20 })
  .then(({ stdout, stderr }) => [{ json: { success: true, output: stdout || stderr } }])
  .catch((e) => [{ json: { success: false, error: e.message, stdout: e.stdout, stderr: e.stderr } }]);
}

